#!/usr/bin/env bash
# qa.sh — 跨端兼容 / 上线验收 QA 环 SOP walkthrough for Web 线上展览开发 (虚拟展厅).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="Web 线上展览开发 (虚拟展厅)"
WORKFLOW="跨端兼容 / 上线验收 QA 环"

usage() {
  cat <<EOF
qa.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./qa.sh             # interactive
  ./qa.sh --dry-run
  ./qa.sh --json
  ./qa.sh --explain
  ./qa.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "跨端兼容 / 上线验收 QA 环" 工作流。

一句话: 从「展厅做完了」到「判定它到底能不能上线」——一套可勾选的验收判据，回答「移动端不崩 / 首屏达标 / 交互可用 / 低端机降级 / 多浏览器通过」。

入门 SOP 共 6 步, 失败模式自检 4 项。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**首屏达标**：在目标网络（如 4G）下首帧可交互时间达标；首屏资产体积在预算内（preload 关键资产、分级加载生效）(evidence: [T03-S001, T03-S004])"
  "**移动端不崩**：真机（含中低端 Android）跑无闪退；显存在预算内（KTX2 + pixelRatio=1 生效）；查 \`renderer.info.memory\` 不持续上涨 (evidence: [T03-S001, T03-S004])"
  "**多浏览器**：Chrome / Firefox / Safari（macOS 与 **iOS 分开测**）；WebGPU 项目尤其测 Safari（timestamp query 不支持等怪癖）(evidence: [T03-S002, T03-S004])"
  "**低端机降级 / fallback 链通**：WebGL2 不可用→回退；\`navigator.gpu\` 判空→WebGL2；扩展可选降级；\`MAX_TEXTURE_SIZE\` 等 limit 查询后再用功能（最小安全值 4096 / 8 sampler）(evidence: [T03-S004, T03-S002])"
  "**交互可用**：动线/相机/热点/导览在触屏与鼠标都可用；AR（如有）真机通；context loss 可恢复（监听 \`webglcontextlost\`/\`webglcontextrestored\`，\`event.preventDefault()\` + 重建资源）(evidence: [T03-S004, T03-S006])"
  "**零 WebGL 错误**：生产构建控制台无 WebGL error（Firefox 32 个后停止描述性报错）(evidence: [T03-S004])"
)
declare -a FAILURE_MODES=(
  "只测自己高配机 → 上线移动端崩：必须中低端真机 + iOS 单独测 (evidence: [T03-S004])"
  "没处理 context loss → 切后台黑屏：监听 webglcontextlost/restored 并重建 (evidence: [T03-S004])"
  "无 fallback → 弱机白屏：确认 WebGPU→WebGL2 链通，扩展可选降级 (evidence: [T03-S002, T03-S004])"
  "precision 默认 highp → 老移动 GPU 渲染损坏：\`GL_FRAGMENT_PRECISION_HIGH\` 检测后再用 highp (evidence: [T03-S004])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "qa-walkthrough"
fi
